class QwenLogFullParser:
    """Main parser with all 1848 templates"""
    
    def __init__(self):
        self.parser_functions = []
        self._load_all_parsers()
    
    def _load_all_parsers(self):
        """Load all parser functions"""
        for i in range(1, 1849):
            is_func_name = f'is_log_template_{i}'
            parse_func_name = f'parse_log_template_{i}'
            
            if is_func_name in globals() and parse_func_name in globals():
                is_func = globals()[is_func_name]
                parse_func = globals()[parse_func_name]
                self.parser_functions.append((is_func, parse_func))
    
    def parse(self, content: str) -> str:
        """Parse a log content and return template"""
        for is_func, parse_func in self.parser_functions:
            try:
                if is_func(content):
                    result = parse_func(content)
                    if isinstance(result, dict) and 'template' in result:
                        return result['template']
            except:
                continue
        return '<*>'  # Unknown

# Convenience function
def parse_log(content: str) -> str:
    """Quick parse function"""
    parser = QwenLogFullParser()
    return parser.parse(content)
